        columnDefinitions={defaultEmployeeColumns}
        onRowClick={(employee: any) => {
          alert(`Clicked on ${employee.fullName}`);
        }} />
</div>;

const ControlledSorting = () => {
  const [orderBy, setOrderBy] = useState<any>([
    { property: "fullName", direction: "asc" },
  ]);

  return (
    <div>
      <div style={{ marginBottom: "16px" }}>
        <strong>Current Sort:</strong>{" "}
        {orderBy.map((o: any, i: number) => (
          <span key={i}>
            {o.property} ({o.direction})
            {i < orderBy.length - 1 && ", "}
          </span>
        ))}
      </div>
      <div className="object-table-container" style={{ height: "600px" }}>
        <ObjectTable
          objectType={Employee}
          columnDefinitions={defaultEmployeeColumns}
          orderBy={orderBy}
          onOrderByChanged={setOrderBy}
        />
      </div>
    </div>
  );
};

const ControlledSelection = () => {
  const [selectedRows, setSelectedRows] = useState<any[]>([]);
  const [isSelectAll, setIsSelectAll] = useState<boolean>(false);
  const handleRowSelection = useCallback(
    (
      selectedRows: any[],
      isSelectAll?: boolean,
    ) => {
      setSelectedRows(selectedRows);
      if (isSelectAll !== undefined) {
        setIsSelectAll(isSelectAll);
      }
    },
    [],
  );

  return (
    <div>
      <div style={{ marginBottom: "16px" }}>
        <strong>Selected:</strong>{" "}
        {isSelectAll ? "All Employees" : `${selectedRows.length} employees`}
        {selectedRows.length > 0 && (
          <button
            style={{
              marginLeft: "16px",
              padding: "4px 8px",
              fontSize: "12px",
              border: "1px solid #d1d5db",
              borderRadius: "4px",
              background: "white",
              cursor: "pointer",
            }}
            onClick={() => {
              setSelectedRows([]);
              setIsSelectAll(false);
            }}
          >
            Clear Selection
          </button>
        )}
      </div>
      <div className="object-table-container" style={{ height: "600px" }}>
        <ObjectTable
          objectType={Employee}
          columnDefinitions={defaultEmployeeColumns}
          selectionMode="multiple"
          selectedRows={selectedRows}
          onRowSelection={handleRowSelection}
        />
      </div>
    </div>
  );
};

